      member.createdAt = Date.now();
    }
    await this.registry.members.save(member);
  }

  async deleteMember(id: string): Promise<void> {
    await this.registry.members.delete(id);
  }

  // Courses
  async listCourses(date?: number): Promise<Course[]> {
